// entity 1 — player spawn (facing +X toward the dummy line). Tagged `player`,
// the EXCLUSIVE target of the combat-demo-reaction.ts `applyDamage` reaction.
// The player archetype declares health (max 100) but NO hitbox, so this tag is
// never matched by a weapon ray — only by the named retaliation reaction.
{
"classname" "player_spawn"
"origin" "48 128 24"
"angles" "0 0 0"
"_tags" "player"
}
// entity 2 — target dummy. Carries health (max 30) + hitbox, so the reference
// pistol's hitscan ray can target it; three 12-damage hits despawn it. Tagged
// `dummy` (EXCLUSIVE to the dummies) so it counts toward the progress threshold.
{
"classname" "target_dummy"
"origin" "176 64 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 3 — target dummy.
{
"classname" "target_dummy"
"origin" "176 112 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 4 — target dummy.
{
"classname" "target_dummy"
"origin" "176 160 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 5 — target dummy. Four dummies, fraction 0.5 means two kills fire
// `dummiesCleared`, which routes 35 damage to the `player` tag.
{
"classname" "target_dummy"
"origin" "176 208 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 6 — light so the dummies are visible
{
"classname" "light"
"origin" "128 128 100"
"light" "300"
"_falloff_range" "2048"
}
// entity 7 — M10 reference enemy. Map-placeable via `"classname"
// "reference_enemy"` because its descriptor (sdk/behaviors/reference/entities.ts,
// spread into the dev mod through `...referenceEntities`) carries health + mesh.
// It also carries the `ai` brain (detection/attack/leash, attackDamage,
// attackCooldownMs, moveSpeed, deathDespawnMs, expReward, and the idle/alert/
// attack/death -> mesh-state map). The CC0 KayKit Knight model animates the four
// FSM states. Placed past the dummy line so the player walks up to it; the
// shipped reference pistol's hitscan kills it (health max 60 + hitbox), firing
// the `enemyKilled` event the EXP store (Task 5) will react to.
{
"classname" "reference_enemy"
"origin" "224 128 16"
"angles" "0 180 0"
"_tags" "enemy"
}
